Javascript.miscCode:
			var MAINTAIN_HEARING = "/ds/MaintainHearing/Hearings";  
		
			function SelectHearing_Popup(){}
			SelectHearing_Popup.raise = {
				eventBinding: {
					singleClicks: [ {element: "SelectTheLastHearingUsingLOVButton"} ],
					keys: [ { key: Key.F6, element: "SelectTheLastHearingUsingLOV" } ]
				}
			};
			SelectHearing_Popup.lower = {
				eventBinding: {
					singleClicks: [ {element: "SelectHearing_CancelBtn"} ],
					keys: [ { key: Key.F4, element: "SelectHearing_Popup" } ]
				}
			};			

			function SelectTheLastHearingUsingLOVButton() {}
			SelectTheLastHearingUsingLOVButton.tabIndex = __tabIdx++;	

			function SelectHearing_OKBtn(){}
			SelectHearing_OKBtn.actionBinding = function()
			{	
				
				var hearingId = Services.getValue(SelectHearingGrid.dataBinding);
				//06-July-2006 Kevin Gichohi (EDS): If there is no past hearing, insert some words ("There is no hearing in the past") into the mandatory field 
				if (null != hearingId && "" != hearingId)
				{
					var type = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/TypeOfHearingCode");
				 	var code = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/VenueCode");
				 	var name = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/VenueName");
				 	var date = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Date");
				 	var time = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Time");
				 	var ln1  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[1]");
				 	var ln2  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[2]");
				 	var ln3  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[3]");
				 	var ln4  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[4]");
				 	var ln5  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/Line[5]");
				 	var pcd  = Services.getValue( MAINTAIN_HEARING+"/Hearing[./HearingID="+hearingId+"]/Address/PostCode");
				 	
				 	strTime = transformToDisplayTime(time, VAR_PAGE_XPATH + "/Tmp/Hearing/ValidTime2");
				 	Services.setValue("/ds/var/tmp/contatenatedLastHearingValue", type + " " + date  + " " + strTime + " " + name);		
				 	Services.setValue(SelectTheLastHearingUsingLOV.dataBinding, type + " " + date  + " " + strTime + " " + name);	 	
					
					Services.setValue(Hearing2Courtname.dataBinding, name);
					//Services.setValue(NEW_HEARING_TMP_PATH + "/Address/AddressId", addressId);
					Services.setValue(Hearing2VenueAddressLine1.dataBinding, ln1);
					Services.setValue(Hearing2VenueAddressLine2.dataBinding, ln2);			
					Services.setValue(Hearing2VenueAddressLine3.dataBinding, ln3);
					Services.setValue(Hearing2VenueAddressLine4.dataBinding, ln4);
					Services.setValue(Hearing2VenuePostcode.dataBinding, pcd);	
				}
				else
				{
					Services.setValue("/ds/var/tmp/contatenatedLastHearingValue", "There is no hearing in the past");		
				 	Services.setValue(SelectTheLastHearingUsingLOV.dataBinding, "");	 	
					
				}								

				FormController.getInstance().hideFormExtensionPopup("SelectHearing");
			}
			
			
			//------------------------  SelectVenue_CancelBtn  -----------------------------------------
			
			function SelectHearing_CancelBtn(){}
			
			
			//------------------------ SelectHearingGrid      ------------------------------------------
			
			function SelectHearingGrid(){}
			SelectHearingGrid.dataBinding = "/ds/OracleReportForm/Service/selectHearingGrid";
			SelectHearingGrid.helpText = "Select the hearing venue";
			SelectHearingGrid.srcData	= "/ds/MaintainHearing/Hearings"; 
			SelectHearingGrid.keyXPath  = "HearingID";
			SelectHearingGrid.rowXPath	= "Hearing";   //[./Date > "+systemdate+"]";  
			SelectHearingGrid.columns = [
				{xpath: "VenueCode"},
				{xpath: "VenueName"},
				{xpath: "TypeOfHearing"},
				{xpath: "Date", sort: CaseManUtils.sortGridDatesDsc, defaultSort:"true", defaultSortOrder:"descending", transformToDisplay: CaseManUtils.formatGridDate},
				{xpath: "Time",  transformToDisplay: CaseManUtils.convertSecondsToTime}
			];	
			
			function loadHearing( caseNumber )
			{
				var params = new ServiceParams();
				params.addSimpleParameter("caseNumber", caseNumber);
				
				//05-July-2006 Kevin Gichohi (EDS): Retrieve only hearings in the past as specified in UC088 and UC089
				//Services.callService("getHearing", params, HearingHandler, true);
				
				Services.callService("getPastHearing", params, HearingHandler, true);
			}

			function HearingHandler(){};
			HearingHandler.onSuccess = function(dom)
			{  	
				//debugger;
				Services.replaceNode("/ds/MaintainHearing", dom.selectSingleNode("/ds/MaintainHearing") );
			}
			
			// This method ensures a time is transformed from the DOM to display correctly.
			// Even if invalid must be displayed as the user entered.
			function transformToDisplayTime(pTime, validTimeFlagXPath)
			{	
				if(Services.getValue(validTimeFlagXPath) == "N")
				{
					return pTime;
				}
				
				if( null != pTime && !isNaN(pTime) )
				{
					var convertedTime = CaseManUtils.convertSecondsToTime(pTime);
					if( null != convertedTime )
					{
						if(CaseManValidationHelper.validateTime(convertedTime))
						{
							return convertedTime;
						}
					}
				}
				return pTime;
			}
